    "content": "{"content":"// SPDX-License-Identifier: GPL-2.0-only\n/*\n *  linux/mm/memory.c\n *\n *  Copyright (C) 1991, 1992, 1993, 1994  Linus Torvalds\n */\n\n/*\n * demand-loading started 01.12.91 - seems it is high on the list of\n * things wanted, and it should be easy to implement. - Linus\n */\n\n/*\n * Ok, demand-loading was easy, shared pages a little bit tricker. Shared\n * pages started 02.12.91, seems to work. - Linus.\n *\n * Tested sharing by executing about 30 /bin/sh: under the old kernel it\n * would have taken more than the 6M I have free, but it worked well as\n * far as I could see.\n *\n * Also corrected some \"invalidate()\"s - I wasn't doing enough of them.\n */\n\n/*\n * Real VM (paging to/from disk) started 18.12.91. Much more work and\n * thought has to go into this. Oh, well..\n * 19.12.91  -  works, somewhat. Sometimes I get faults, don't know why.\n *\t\tFound it. Everything seems to work now.\n * 20.12.91  -  Ok, making the swap-device changeable like the root.\n */\n\n/*\n * 05.04.94  -  Multi-page memory management added for v1.1.\n *              Idea by Alex Bligh (alex@cconcepts.co.uk)\n *\n * 16.07.99  -  Support of BIGMEM added by Gerhard Wichert, Siemens AG\n *\t\t(Gerhard.Wichert@pdb.siemens.de)\n *\n * Aug/Sep 2004 Changed to four level page tables (Andi Kleen)\n */\n\n#include <linux/kernel_stat.h>\n#include <linux/mm.h>\n#include <linux/mm_inline.h>\n#include <linux/sched/mm.h>\n#include <linux/sched/numa_balancing.h>\n#include <linux/sched/task.h>\n#include <linux/hugetlb.h>\n#include <linux/mman.h>\n#include <linux/swap.h>\n#include <linux/highmem.h>\n#include <linux/pagemap.h>\n#include <linux/memremap.h>\n#include <linux/kmsan.h>\n#include <linux/ksm.h>\n#include <linux/rmap.h>\n#include <linux/export.h>\n#include <linux/delayacct.h>\n#include <linux/init.h>\n#include <linux/writeback.h>\n#include <linux/memcontrol.h>\n#include <linux/mmu_notifier.h>\n#include <linux/leafops.h>\n#include <linux/elf.h>\n#include <linux/gfp.h>\n#include <linux/migrate.h>\n#include <linux/string.h>\n#include <linux/shmem_fs.h>\n#include <linux/memory-tiers.h>\n#include <linux/debugfs.h>\n#include <linux/userfaultfd_k.h>\n#include <linux/dax.h>\n#include <linux/oom.h>\n#include <linux/numa.h>\n#include <linux/perf_event.h>\n#include <linux/ptrace.h>\n#include <linux/vmalloc.h>\n#include <linux/sched/sysctl.h>\n#include <linux/pgalloc.h>\n#include <linux/uaccess.h>\n\n#include <trace/events/kmem.h>\n\n#include <asm/io.h>\n#include <asm/mmu_context.h>\n#include <asm/tlb.h>\n#include <asm/tlbflush.h>\n\n#include \"pgalloc-track.h\"\n#include \"internal.h\"\n#include \"swap.h\"\n\n#if defined(LAST_CPUPID_NOT_IN_PAGE_FLAGS) && !defined(CONFIG_COMPILE_TEST)\n#warning Unfortunate NUMA and NUMA Balancing config, growing page-frame for last_cpupid.\n#endif\n\nstatic vm_fault_t do_fault(struct vm_fault *vmf);\nstatic vm_fault_t do_anonymous_page(struct vm_fault *vmf);\nstatic bool vmf_pte_changed(struct vm_fault *vmf);\n\n/*\n * Return true if the original pte was a uffd-wp pte marker (so the pte was\n * wr-protected).\n */\nstatic __always_inline bool vmf_orig_pte_uffd_wp(struct vm_fault *vmf)\n{\n\tif (!userfaultfd_wp(vmf->vma))\n\t\treturn false;\n\tif (!(vmf->flags & FAULT_FLAG_ORIG_PTE_VALID))\n\t\treturn false;\n\n\treturn pte_is_uffd_wp_marker(vmf->orig_pte);\n}\n\n/*\n * Randomize the address space (stacks, mmaps, brk, etc.).\n *\n * ( When CONFIG_COMPAT_BRK=y we exclude brk from randomization,\n *   as ancient (libc5 based) binaries can segfault. )\n */\nint randomize_va_space __read_mostly =\n#ifdef CONFIG_COMPAT_BRK\n\t\t\t\t\t1;\n#else\n\t\t\t\t\t2;\n#endif\n\nstatic const struct ctl_table mmu_sysctl_table[] = {\n\t{\n\t\t.procname\t= \"randomize_va_space\",\n\t\t.data\t\t= &randomize_va_space,\n\t\t.maxlen\t\t= sizeof(int),\n\t\t.mode\t\t= 0644,\n\t\t.proc_handler\t= proc_dointvec,\n\t},\n};\n\nstatic int __init init_mm_sysctl(void)\n{\n\tregister_sysctl_init(\"kernel\", mmu_sysctl_table);\n\treturn 0;\n}\n\nsubsys_initcall(init_mm_sysctl);\n\n#ifndef arch_wants_old_prefaulted_pte\nstatic inline bool arch_wants_old_prefaulted_pte(void)\n{\n\t/*\n\t * Transitioning a PTE from 'old' to 'young' can be expensive on\n\t * some architectures, even if it's performed in hardware. By\n\t * default, \"false\" means prefaulted entries will be 'young'.\n\t */\n\treturn false;\n}\n#endif\n\nstatic int __init disable_randmaps(char *s)\n{\n\trandomize_va_space = 0;\n\treturn 1;\n}\n__setup(\"norandmaps\", disable_randmaps);\n\nunsigned long highest_memmap_pfn __read_mostly;\n\nvoid mm_trace_rss_stat(struct mm_struct *mm, int member)\n{\n\ttrace_rss_stat(mm, member);\n}\n\n/*\n * Note: this doesn't free the actual pages themselves. That\n * has been handled earlier when unmapping all the memory regions.\n */\nstatic void free_pte_range(struct mmu_gather *tlb, pmd_t *pmd,\n\t\t\t   unsigned long addr)\n{\n\tpgtable_t token = pmd_pgtable(*pmd);\n\tpmd_clear(pmd);\n\tpte_free_tlb(tlb, token, addr);\n\tmm_dec_nr_ptes(tlb->mm);\n}\n\nstatic inline void free_pmd_range(struct mmu_gather *tlb, pud_t *pud,\n\t\t\t\tunsigned long addr, unsigned long end,\n\t\t\t\tunsigned long floor, unsigned long ceiling)\n{\n\tpmd_t *pmd;\n\tunsigned long next;\n\tunsigned long start;\n\n\tstart = addr;\n\tpmd = pmd_offset(pud, addr);\n\tdo {\n\t\tnext = pmd_addr_end(addr, end);\n\t\tif (pmd_none_or_clear_bad(pmd))\n\t\t\tcontinue;\n\t\tfree_pte_range(tlb, pmd, addr);\n\t} while (pmd++, addr = next, addr != end);\n\n\tstart &= PUD_MASK;\n\tif (start < floor)\n\t\treturn;\n\tif (ceiling) {\n\t\tceiling &= PUD_MASK;\n\t\tif (!ceiling)\n\t\t\treturn;\n\t}\n\tif (end - 1 > ceiling - 1)\n\t\treturn;\n\n\tpmd = pmd_offset(pud, start);\n\tpud_clear(pud);\n\tpmd_free_tlb(tlb, pmd, start);\n\tmm_dec_nr_pmds(tlb->mm);\n}\n\nstatic inline void free_pud_range(struct mmu_gather *tlb, p4d_t *p4d,\n\t\t\t\tunsigned long addr, unsigned long end,\n\t\t\t\tunsigned long floor, unsigned long ceiling)\n{\n\tpud_t *pud;\n\tunsigned long next;\n\tunsigned long start;\n\n\tstart = addr;\n\tpud = pud_offset(p4d, addr);\n\tdo {\n\t\tnext = pud_addr_end(addr, end);\n\t\tif (pud_none_or_clear_bad(pud))\n\t\t\tcontinue;\n\t\tfree_pmd_range(tlb, pud, addr, next, floor, ceiling);\n\t} while (pud++, addr = next, addr != end);\n\n\tstart &= P4D_MASK;\n\tif (start < floor)\n\t\treturn;\n\tif (ceiling) {\n\t\tceiling &= P4D_MASK;\n\t\tif (!ceiling)\n\t\t\treturn;\n\t}\n\tif (end - 1 > ceiling - 1)\n\t\treturn;\n\n\tpud = pud_offset(p4d, start);\n\tp4d_clear(p4d);\n\tpud_free_tlb(tlb, pud, start);\n\tmm_dec_nr_puds(tlb->mm);\n}\n\nstatic inline void free_p4d_range(struct mmu_gather *tlb, pgd_t *pgd,\n\t\t\t\tunsigned long addr, unsigned long end,\n\t\t\t\tunsigned long floor, unsigned long ceiling)\n{\n\tp4d_t *p4d;\n\tunsigned long next;\n\tunsigned long start;\n\n\tstart = addr;\n\tp4d = p4d_offset(pgd, addr);\n\tdo {\n\t\tnext = p4d_addr_end(addr, end);\n\t\tif (p4d_none_or_clear_bad(p4d))\n\t\t\tcontinue;\n\t\tfree_pud_range(tlb, p4d, addr, next, floor, ceiling);\n\t} while (p4d++, addr = next, addr != end);\n\n\tstart &= PGDIR_MASK;\n\tif (start < floor)\n\t\treturn;\n\tif (ceiling) {\n\t\tceiling &= PGDIR_MASK;\n\t\tif (!ceiling)\n\t\t\treturn;\n\t}\n\tif (end - 1 > ceiling - 1)\n\t\treturn;\n\n\tp4d = p4d_offset(pgd, start);\n\tpgd_clear(pgd);\n\tp4d_free_tlb(tlb, p4d, start);\n}\n\n/**\n * free_pgd_range - Unmap and free page tables in the range\n * @tlb: the mmu_gather containing pending TLB flush info\n * @addr: virtual address start\n * @end: virtual address end\n * @floor: lowest address boundary\n * @ceiling: highest address boundary\n *\n * This function tears down all user-level page tables in the\n * specified virtual address range [@addr..@end). It is part of\n * the memory unmap flow.\n */\nvoid free_pgd_range(struct mmu_gather *tlb,\n\t\t\tunsigned long addr, unsigned long end,\n\t\t\tunsigned long floor, unsigned long ceiling)\n{\n\tpgd_t *pgd;\n\tunsigned long next;\n\n\t/*\n\t * The next few lines have given us lots of grief...\n\t *\n\t * Why are we testing PMD* at this top level?  Because often\n\t * there will be no work to do at all, and we'd prefer not to\n\t * go all the way down to the bottom just to discover that.\n\t *\n\t * Why all these \"- 1\"s?  Because 0 represents both the bottom\n\t * of the address space and the top of it (using -1 for the\n\t * top wouldn't help much: the masks would do the wrong thing).\n\t * The rule is that addr 0 and floor 0 refer to the bottom of\n\t * the address space, but end 0 and ceiling 0 refer to the top\n\t * Comparisons need to use \"end - 1\" and \"ceiling - 1\" (though\n\t * that end 0 case should be mythical).\n\t *\n\t * Wherever addr is brought up or ceiling brought down, we must\n\t * be careful to reject \"the opposite 0\" before it confuses the\n\t * subsequent tests.  But what about where end is brought down\n\t * by PMD_SIZE below? no, end can't go down to 0 there.\n\t *\n\t * Whereas we round start (addr) and ceiling down, by different\n\t * masks at different levels, in order to test whether a table\n\t * now has no other vmas using it, so can be freed, we don't\n\t * bother to round floor or end up - the tests don't need that.\n\t */\n\n\taddr &= PMD_MASK;\n\tif (addr < floor) {\n\t\taddr += PMD_SIZE;\n\t\tif (!addr)\n\t\t\treturn;\n\t}\n\tif (ceiling) {\n\t\tceiling &= PMD_MASK;\n\t\tif (!ceiling)\n\t\t\treturn;\n\t}\n\tif (end - 1 > ceiling - 1)\n\t\tend -= PMD_SIZE;\n\tif (addr > end - 1)\n\t\treturn;\n\t/*\n\t * We add page table cache pages with PAGE_SIZE,\n\t * (see pte_free_tlb()), flush the tlb if we need\n\t */\n\ttlb_change_page_size(tlb, PAGE_SIZE);\n\tpgd = pgd_offset(tlb->mm, addr);\n\tdo {\n\t\tnext = pgd_addr_end(addr, end);\n\t\tif (pgd_none_or_clear_bad(pgd))\n\t\t\tcontinue;\n\t\tfree_p4d_range(tlb, pgd, addr, next, floor, ceiling);\n\t} while (pgd++, addr = next, addr != end);\n}\n\n/**\n * free_pgtables() - Free a range of page tables\n * @tlb: The mmu gather\n * @unmap: The unmap_desc\n *\n * Note: pg_start and pg_end are provided to indicate the absolute range of the\n * page tables that should be removed.  This can differ from the vma mappings on\n * some archs that may have mappings that need to be removed outside the vmas.\n * Note that the prev->vm_end and next->vm_start are often used.\n *\n * The vma_end differs from the pg_end when a dup_mmap() failed and the tree has\n * unrelated data to the mm_struct being torn down.\n */\nvoid free_pgtables(struct mmu_gather *tlb, struct unmap_desc *unmap)\n{\n\tstruct unlink_vma_file_batch vb;\n\tstruct ma_state *mas = unmap->mas;\n\tstruct vm_area_struct *vma = unmap->first;\n\n\t/*\n\t * Note: USER_PGTABLES_CEILING may be passed as the value of pg_end and\n\t * may be 0.  Underflow is expected in this case.  Otherwise the\n\t * pagetable end is exclusive.  vma_end is exclusive.  The last vma\n\t * address should never be larger than the pagetable end.\n\t */\n\tWARN_ON_ONCE(unmap->vma_end - 1 > unmap->pg_end - 1);\n\n\ttlb_free_vmas(tlb);\n\n\tdo {\n\t\tunsigned long addr = vma->vm_start;\n\t\tstruct vm_area_struct *next;\n\n\t\tnext = mas_find(mas, unmap->tree_end - 1);\n\n\t\t/*\n\t\t * Hide vma from rmap and truncate_pagecache before freeing\n\t\t * pgtables\n\t\t */\n\t\tif (unmap->mm_wr_locked)\n\t\t\tvma_start_write(vma);\n\n... [Diff truncated. Dropped 6821 lines] ...\n\n\n\t/* Avoid triggering the temporary warning in __get_user_pages */\n\tif (!vma_lookup(mm, addr)) {\n\t\terr = -EFAULT;\n\t\tgoto out;\n\t}\n\n\twhile (len) {\n\t\tint bytes, offset, retval;\n\t\tvoid *maddr;\n\t\tstruct folio *folio;\n\t\tstruct page *page;\n\t\tstruct vm_area_struct *vma = NULL;\n\n\t\tpage = get_user_page_vma_remote(mm, addr, gup_flags, &vma);\n\t\tif (IS_ERR(page)) {\n\t\t\t/*\n\t\t\t * Treat as a total failure for now until we decide how\n\t\t\t * to handle the CONFIG_HAVE_IOREMAP_PROT case and\n\t\t\t * stack expansion.\n\t\t\t */\n\t\t\t*(char *)buf = '\\0';\n\t\t\terr = -EFAULT;\n\t\t\tgoto out;\n\t\t}\n\n\t\tfolio = page_folio(page);\n\t\tbytes = len;\n\t\toffset = addr & (PAGE_SIZE - 1);\n\t\tif (bytes > PAGE_SIZE - offset)\n\t\t\tbytes = PAGE_SIZE - offset;\n\n\t\tmaddr = kmap_local_folio(folio, folio_page_idx(folio, page) * PAGE_SIZE);\n\t\tretval = strscpy(buf, maddr + offset, bytes);\n\t\tif (retval >= 0) {\n\t\t\t/* Found the end of the string */\n\t\t\tbuf += retval;\n\t\t\tfolio_release_kmap(folio, maddr);\n\t\t\tbreak;\n\t\t}\n\n\t\tbuf += bytes - 1;\n\t\t/*\n\t\t * Because strscpy always NUL terminates we need to\n\t\t * copy the last byte in the page if we are going to\n\t\t * load more pages\n\t\t */\n\t\tif (bytes != len) {\n\t\t\taddr += bytes - 1;\n\t\t\tcopy_from_user_page(vma, page, addr, buf, maddr + (PAGE_SIZE - 1), 1);\n\t\t\tbuf += 1;\n\t\t\taddr += 1;\n\t\t}\n\t\tlen -= bytes;\n\n\t\tfolio_release_kmap(folio, maddr);\n\t}\n\nout:\n\tmmap_read_unlock(mm);\n\tif (err)\n\t\treturn err;\n\treturn buf - old_buf;\n}\n\n/**\n * copy_remote_vm_str - copy a string from another process's address space.\n * @tsk:\tthe task of the target address space\n * @addr:\tstart address to read from\n * @buf:\tdestination buffer\n * @len:\tnumber of bytes to copy\n * @gup_flags:\tflags modifying lookup behaviour\n *\n * The caller must hold a reference on @mm.\n *\n * Return: number of bytes copied from @addr (source) to @buf (destination);\n * not including the trailing NUL. Always guaranteed to leave NUL-terminated\n * buffer. On any error, return -EFAULT.\n */\nint copy_remote_vm_str(struct task_struct *tsk, unsigned long addr,\n\t\t       void *buf, int len, unsigned int gup_flags)\n{\n\tstruct mm_struct *mm;\n\tint ret;\n\n\tif (unlikely(len == 0))\n\t\treturn 0;\n\n\tmm = get_task_mm(tsk);\n\tif (!mm) {\n\t\t*(char *)buf = '\\0';\n\t\treturn -EFAULT;\n\t}\n\n\tret = __copy_remote_vm_str(mm, addr, buf, len, gup_flags);\n\n\tmmput(mm);\n\n\treturn ret;\n}\nEXPORT_SYMBOL_GPL(copy_remote_vm_str);\n#endif /* CONFIG_BPF_SYSCALL */\n\n/*\n * Print the name of a VMA.\n */\nvoid print_vma_addr(char *prefix, unsigned long ip)\n{\n\tstruct mm_struct *mm = current->mm;\n\tstruct vm_area_struct *vma;\n\n\t/*\n\t * we might be running from an atomic context so we cannot sleep\n\t */\n\tif (!mmap_read_trylock(mm))\n\t\treturn;\n\n\tvma = vma_lookup(mm, ip);\n\tif (vma && vma->vm_file) {\n\t\tstruct file *f = vma->vm_file;\n\t\tip -= vma->vm_start;\n\t\tip += vma->vm_pgoff << PAGE_SHIFT;\n\t\tprintk(\"%s%pD[%lx,%lx+%lx]\", prefix, f, ip,\n\t\t\t\tvma->vm_start,\n\t\t\t\tvma->vm_end - vma->vm_start);\n\t}\n\tmmap_read_unlock(mm);\n}\n\n#if defined(CONFIG_PROVE_LOCKING) || defined(CONFIG_DEBUG_ATOMIC_SLEEP)\nvoid __might_fault(const char *file, int line)\n{\n\tif (pagefault_disabled())\n\t\treturn;\n\t__might_sleep(file, line);\n\tif (current->mm)\n\t\tmight_lock_read(&current->mm->mmap_lock);\n}\nEXPORT_SYMBOL(__might_fault);\n#endif\n\n#if defined(CONFIG_TRANSPARENT_HUGEPAGE) || defined(CONFIG_HUGETLBFS)\n/*\n * Process all subpages of the specified huge page with the specified\n * operation.  The target subpage will be processed last to keep its\n * cache lines hot.\n */\nstatic inline int process_huge_page(\n\tunsigned long addr_hint, unsigned int nr_pages,\n\tint (*process_subpage)(unsigned long addr, int idx, void *arg),\n\tvoid *arg)\n{\n\tint i, n, base, l, ret;\n\tunsigned long addr = addr_hint &\n\t\t~(((unsigned long)nr_pages << PAGE_SHIFT) - 1);\n\n\t/* Process target subpage last to keep its cache lines hot */\n\tmight_sleep();\n\tn = (addr_hint - addr) / PAGE_SIZE;\n\tif (2 * n <= nr_pages) {\n\t\t/* If target subpage in first half of huge page */\n\t\tbase = 0;\n\t\tl = n;\n\t\t/* Process subpages at the end of huge page */\n\t\tfor (i = nr_pages - 1; i >= 2 * n; i--) {\n\t\t\tcond_resched();\n\t\t\tret = process_subpage(addr + i * PAGE_SIZE, i, arg);\n\t\t\tif (ret)\n\t\t\t\treturn ret;\n\t\t}\n\t} else {\n\t\t/* If target subpage in second half of huge page */\n\t\tbase = nr_pa