PAGECACHE_ORDER limit does not apply to\n * it.  Same to PFNMAPs where there's neither page* nor pagecache.\n */\n#define THP_ORDERS_ALL_SPECIAL_DAX\t\\\n\t(BIT(PMD_ORDER) | BIT(PUD_ORDER))\n#define THP_ORDERS_ALL_FILE_DEFAULT\t\\\n\t((BIT(MAX_PAGECACHE_ORDER + 1) - 1) & ~BIT(0))\n\n/*\n * Mask of all large folio orders supported for THP.\n */\n#define THP_ORDERS_ALL\t\\\n\t(THP_ORDERS_ALL_ANON | THP_ORDERS_ALL_SPECIAL_DAX | THP_ORDERS_ALL_FILE_DEFAULT)\n\nenum tva_type {\n\tTVA_SMAPS,\t\t/* Exposing \"THPeligible:\" in smaps. */\n\tTVA_PAGEFAULT,\t\t/* Serving a page fault. */\n\tTVA_KHUGEPAGED,\t\t/* Khugepaged collapse. */\n\tTVA_FORCED_COLLAPSE,\t/* Forced collapse (e.g. MADV_COLLAPSE). */\n};\n\n#define thp_vma_allowable_order(vma, vm_flags, type, order) \\\n\t(!!thp_vma_allowable_orders(vma, vm_flags, type, BIT(order)))\n\n#define split_folio(f) split_folio_to_list(f, NULL)\n\n#ifdef CONFIG_PGTABLE_HAS_HUGE_LEAVES\n#define HPAGE_PMD_SHIFT PMD_SHIFT\n#define HPAGE_PUD_SHIFT PUD_SHIFT\n#else\n#define HPAGE_PMD_SHIFT ({ BUILD_BUG(); 0; })\n#define HPAGE_PUD_SHIFT ({ BUILD_BUG(); 0; })\n#endif\n\n#define HPAGE_PMD_ORDER (HPAGE_PMD_SHIFT-PAGE_SHIFT)\n#define HPAGE_PMD_NR (1<<HPAGE_PMD_ORDER)\n#define HPAGE_PMD_MASK\t(~(HPAGE_PMD_SIZE - 1))\n#define HPAGE_PMD_SIZE\t((1UL) << HPAGE_PMD_SHIFT)\n\n#define HPAGE_PUD_ORDER (HPAGE_PUD_SHIFT-PAGE_SHIFT)\n#define HPAGE_PUD_NR (1<<HPAGE_PUD_ORDER)\n#define HPAGE_PUD_MASK\t(~(HPAGE_PUD_SIZE - 1))\n#define HPAGE_PUD_SIZE\t((1UL) << HPAGE_PUD_SHIFT)\n\nenum mthp_stat_item {\n\tMTHP_STAT_ANON_FAULT_ALLOC,\n\tMTHP_STAT_ANON_FAULT_FALLBACK,\n\tMTHP_STAT_ANON_FAULT_FALLBACK_CHARGE,\n\tMTHP_STAT_ZSWPOUT,\n\tMTHP_STAT_SWPIN,\n\tMTHP_STAT_SWPIN_FALLBACK,\n\tMTHP_STAT_SWPIN_FALLBACK_CHARGE,\n\tMTHP_STAT_SWPOUT,\n\tMTHP_STAT_SWPOUT_FALLBACK,\n\tMTHP_STAT_SHMEM_ALLOC,\n\tMTHP_STAT_SHMEM_FALLBACK,\n\tMTHP_STAT_SHMEM_FALLBACK_CHARGE,\n\tMTHP_STAT_SPLIT,\n\tMTHP_STAT_SPLIT_FAILED,\n\tMTHP_STAT_SPLIT_DEFERRED,\n\tMTHP_STAT_NR_ANON,\n\tMTHP_STAT_NR_ANON_PARTIALLY_MAPPED,\n\t__MTHP_STAT_COUNT\n};\n\n#if defined(CONFIG_TRANSPARENT_HUGEPAGE) && defined(CONFIG_SYSFS)\nstruct mthp_stat {\n\tunsigned long stats[ilog2(MAX_PTRS_PER_PTE) + 1][__MTHP_STAT_COUNT];\n};\n\nDECLARE_PER_CPU(struct mthp_stat, mthp_stats);\n\nstatic inline void mod_mthp_stat(int order, enum mthp_stat_item item, int delta)\n{\n\tif (order <= 0 || order > PMD_ORDER)\n\t\treturn;\n\n\tthis_cpu_add(mthp_stats.stats[order][item], delta);\n}\n\nstatic inline void count_mthp_stat(int order, enum mthp_stat_item item)\n{\n\tmod_mthp_stat(order, item, 1);\n}\n\n#else\nstatic inline void mod_mthp_stat(int order, enum mthp_stat_item item, int delta)\n{\n}\n\nstatic inline void count_mthp_stat(int order, enum mthp_stat_item item)\n{\n}\n#endif\n\n#ifdef CONFIG_TRANSPARENT_HUGEPAGE\n\nextern unsigned long transparent_hugepage_flags;\nextern unsigned long huge_anon_orders_always;\nextern unsigned long huge_anon_orders_madvise;\nextern unsigned long huge_anon_orders_inherit;\n\nstatic inline bool hugepage_global_enabled(void)\n{\n\treturn transparent_hugepage_flags &\n\t\t\t((1<<TRANSPARENT_HUGEPAGE_FLAG) |\n\t\t\t(1<<TRANSPARENT_HUGEPAGE_REQ_MADV_FLAG));\n}\n\nstatic inline bool hugepage_global_always(void)\n{\n\treturn transparent_hugepage_flags &\n\t\t\t(1<<TRANSPARENT_HUGEPAGE_FLAG);\n}\n\nstatic inline int highest_order(unsigned long orders)\n{\n\treturn fls_long(orders) - 1;\n}\n\nstatic inline int next_order(unsigned long *orders, int prev)\n{\n\t*orders &= ~BIT(prev);\n\treturn highest_order(*orders);\n}\n\n/*\n * Do the below checks:\n *   - For file vma, check if the linear page offset of vma is\n *     order-aligned within the file.  The hugepage is\n *     guaranteed to be order-aligned within the file, but we must\n *     check that the order-aligned addresses in the VMA map to\n *     order-aligned offsets within the file, else the hugepage will\n *     not be mappable.\n *   - For all vmas, check if the haddr is in an aligned hugepage\n *     area.\n */\nstatic inline bool thp_vma_suitable_order(struct vm_area_struct *vma,\n\t\tunsigned long addr, int order)\n{\n\tunsigned long hpage_size = PAGE_SIZE << order;\n\tunsigned long haddr;\n\n\t/* Don't have to check pgoff for anonymous vma */\n\tif (!vma_is_anonymous(vma)) {\n\t\tif (!IS_ALIGNED((vma->vm_start >> PAGE_SHIFT) - vma->vm_pgoff,\n\t\t\t\thpage_size >> PAGE_SHIFT))\n\t\t\treturn false;\n\t}\n\n\thaddr = ALIGN_DOWN(addr, hpage_size);\n\n\tif (haddr < vma->vm_start || haddr + hpage_size > vma->vm_end)\n\t\treturn false;\n\treturn true;\n}\n\n/*\n * Filter the bitfield of input orders to the ones suitable for use in the vma.\n * See thp_vma_suitable_order().\n * All orders that pass the checks are returned as a bitfield.\n */\nstatic inline unsigned long thp_vma_suitable_orders(struct vm_area_struct *vma,\n\t\tunsigned long addr, unsigned long orders)\n{\n\tint order;\n\n\t/*\n\t * Iterate over orders, highest to lowest, removing orders that don't\n\t * meet alignment requirements from the set. Exit loop at first order\n\t * that meets requirements, since all lower orders must also meet\n\t * requirements.\n\t */\n\n\torder = highest_order(orders);\n\n\twhile (orders) {\n\t\tif (thp_vma_suitable_order(vma, addr, order))\n\t\t\tbreak;\n\t\torder = next_order(&orders, order);\n\t}\n\n\treturn orders;\n}\n\nunsigned long __thp_vma_allowable_orders(struct vm_area_struct *vma,\n\t\t\t\t\t vm_flags_t vm_flags,\n\t\t\t\t\t enum tva_type type,\n\t\t\t\t\t unsigned long orders);\n\n/**\n * thp_vma_allowable_orders - determine hugepage orders that are allowed for vma\n * @vma:  the vm area to check\n * @vm_flags: use these vm_flags instead of vma->vm_flags\n * @type: TVA type\n * @orders: bitfield of all orders to consider\n *\n * Calculates the intersection of the requested hugepage orders and the allowed\n * hugepage orders for the provided vma. Permitted orders are encoded as a set\n * bit at the corresponding bit position (bit-2 corresponds to order-2, bit-3\n * corresponds to order-3, etc). Order-0 is never considered a hugepage order.\n *\n * Return: bitfield of orders allowed for hugepage in the vma. 0 if no hugepage\n * orders are allowed.\n */\nstatic inline\nunsigned long thp_vma_allowable_orders(struct vm_area_struct *vma,\n\t\t\t\t       vm_flags_t vm_flags,\n\t\t\t\t       enum tva_type type,\n\t\t\t\t       unsigned long orders)\n{\n\t/*\n\t * Optimization to check if required orders are enabled early. Only\n\t * forced collapse ignores sysfs configs.\n\t */\n\tif (type != TVA_FORCED_COLLAPSE && vma_is_anonymous(vma)) {\n\t\tunsigned long mask = READ_ONCE(huge_anon_orders_always);\n\n\t\tif (vm_flags & VM_HUGEPAGE)\n\t\t\tmask |= READ_ONCE(huge_anon_orders_madvise);\n\t\tif (hugepage_global_always() ||\n\t\t    ((vm_flags & VM_HUGEPAGE) && hugepage_global_enabled()))\n\t\t\tmask |= READ_ONCE(huge_anon_orders_inherit);\n\n\t\torders &= mask;\n\t\tif (!orders)\n\t\t\treturn 0;\n\t}\n\n\treturn __thp_vma_allowable_orders(vma, vm_flags, type, orders);\n}\n\nstruct thpsize {\n\tstruct kobject kobj;\n\tstruct list_head node;\n\tint order;\n};\n\n#define to_thpsize(kobj) container_of(kobj, struct thpsize, kobj)\n\n#define transparent_hugepage_use_zero_page()\t\t\t\t\\\n\t(transparent_hugepage_flags &\t\t\t\t\t\\\n\t (1<<TRANSPARENT_HUGEPAGE_USE_ZERO_PAGE_FLAG))\n\n/*\n * Check whether THPs are explicitly disabled for this VMA, for example,\n * through madvise or prctl.\n */\nstatic inline bool vma_thp_disabled(struct vm_area_struct *vma,\n\t\tvm_flags_t vm_flags, bool forced_collapse)\n{\n\t/* Are THPs disabled for this VMA? */\n\tif (vm_flags & VM_NOHUGEPAGE)\n\t\treturn true;\n\t/* Are THPs disabled for all VMAs in the whole process? */\n\tif (mm_flags_test(MMF_DISABLE_THP_COMPLETELY, vma->vm_mm))\n\t\treturn true;\n\t/*\n\t * Are THPs disabled only for VMAs where we didn't get an explicit\n\t * advise to use them?\n\t */\n\tif (vm_flags & VM_HUGEPAGE)\n\t\treturn false;\n\t/*\n\t * Forcing a collapse (e.g., madv_collapse), is a clear advice to\n\t * use THPs.\n\t */\n\tif (forced_collapse)\n\t\treturn false;\n\treturn mm_flags_test(MMF_DISABLE_THP_EXCEPT_ADVISED, vma->vm_mm);\n}\n\nstatic inline bool thp_disabled_by_hw(void)\n{\n\t/* If the hardware/firmware marked hugepage support disabled. */\n\treturn transparent_hugepage_flags & (1 << TRANSPARENT_HUGEPAGE_UNSUPPORTED);\n}\n\nunsigned long thp_get_unmapped_area(struct file *filp, unsigned long addr,\n\t\tunsigned long len, unsigned long pgoff, unsigned long flags);\nunsigned long thp_get_unmapped_area_vmflags(struct file *filp, unsigned long addr,\n\t\tunsigned long len, unsigned long pgoff, unsigned long flags,\n\t\tvm_flags_t vm_flags);\n\nenum split_type {\n\tSPLIT_TYPE_UNIFORM,\n\tSPLIT_TYPE_NON_UNIFORM,\n};\n\nint __split_huge_page_to_list_to_order(struct page *page, struct list_head *list,\n\t\tunsigned int new_order);\nint folio_split_unmapped(struct folio *folio, unsigned int new_order);\nunsigned int min_order_for_split(struct folio *folio);\nint split_folio_to_list(struct folio *folio, struct list_head *list);\nint folio_check_splittable(struct folio *folio, unsigned int new_order,\n\t\t\t   enum split_type split_type);\nint folio_split(struct folio *folio, unsigned int new_order, struct page *page,\n\t\tstruct list_head *list);\n\nstatic inline int split_huge_page_to_list_to_order(struct page *page, struct list_head *list,\n\t\tunsigned int new_order)\n{\n\treturn __split_huge_page_to_list_to_order(page, list, new_order);\n}\nstatic inline int split_huge_page_to_order(struct page *page, unsigned int new_order)\n{\n\treturn split_huge_page_to_list_to_order(page, NULL, new_order);\n}\n\n/**\n * try_folio_split_to_order() - try to split a @folio at @page to @new_order\n * using non uniform split.\n * @folio: folio to be split\n * @page: split to @new_order at the given page\n * @new_order: the target split order\n *\n * Try to split a @folio at @page using non uniform split to @new_order, if\n * non unifo